import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!email.trim() || !password) {
      setError('Please provide your email and password.');
      return;
    }

    // TODO: call backend auth API
    // For now just pretend success and navigate home
    navigate('/');
  };

  return (
    <div className="max-w-md mx-auto mt-12 p-6 bg-[#0a0a0a] rounded-lg shadow-xl border border-[#C5A059]/30 glass text-white">
      <h2 className="ghost-header-md text-center mb-4">Sign In</h2>
      <form onSubmit={handleSubmit}>
        <label className="block mb-2">
          <span className="label-tech-luxury opacity-60 mb-1">Email</span>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="mt-1 block w-full rounded bg-[#020202] border border-slate-700/50 text-white shadow-sm focus:ring-[#00FF41]/50 focus:border-[#00FF41]/50"
            placeholder="you@example.com"
            required
          />
        </label>

        <label className="block mb-4">
          <span className="label-tech-luxury opacity-60 mb-1">Password</span>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="mt-1 block w-full rounded bg-[#020202] border border-slate-700/50 text-white shadow-sm focus:ring-[#00FF41]/50 focus:border-[#00FF41]/50"
            placeholder="Your password"
            required
          />
        </label>

        {error && <div className="text-[#FF3E3E] mb-3 text-sm">{error}</div>}

        <button
          type="submit"
          className="label-tech-pulse w-full bg-[#00FF41] text-[#020202] py-2 rounded font-bold hover:bg-[#00FF41]/80 disabled:opacity-50 transition-colors"
        >
          Sign In
        </button>
      </form>

      <div className="mt-4 text-center">
        <p className="text-sm text-slate-300">Don't have an account?</p>
        <Link to="/register" className="label-tech-pulse hover:text-[#00FF41]/80">
          Create an account
        </Link>
        <div className="mt-2">
          <Link to="/forgot-password" className="label-tech-pulse hover:text-[#00FF41]/80">
            Forgot password?
          </Link>
        </div>
      </div>
    </div>
  );
};

export default Login;
